// Parametric rounded storage tray / box.
//
// A generic open-top tray: a rounded outer shell with a hollowed cavity and an
// optional row of internal dividers. Every dimension someone would actually want
// to change is exposed as a Customizer knob via api.params(), so the same model
// covers a tiny coin cup or a wide desk organizer just by dragging sliders.

const { Manifold, CrossSection } = api;

const p = api.params({
  width: {
    type: 'number', default: 90, min: 20, max: 200, step: 1, unit: 'mm',
    label: 'Outer width (X)',
    help: 'Overall footprint along X. Dividers split this dimension.',
  },
  depth: {
    type: 'number', default: 60, min: 20, max: 200, step: 1, unit: 'mm',
    label: 'Outer depth (Y)',
  },
  height: {
    type: 'number', default: 35, min: 8, max: 120, step: 1, unit: 'mm',
    label: 'Outer height (Z)',
  },
  wall: {
    type: 'number', default: 2.4, min: 0.8, max: 12, step: 0.2, unit: 'mm',
    label: 'Wall thickness',
    help: 'Side-wall thickness. The cavity shrinks by this on every side.',
  },
  floor: {
    type: 'number', default: 2.0, min: 0.8, max: 12, step: 0.2, unit: 'mm',
    label: 'Floor thickness',
  },
  radius: {
    type: 'number', default: 6, min: 0, max: 40, step: 0.5, unit: 'mm',
    label: 'Corner radius',
    help: 'Outer corner rounding. Ignored when corner style is "square".',
  },
  dividers: {
    type: 'int', default: 0, min: 0, max: 8,
    label: 'Internal dividers',
    help: 'Number of cross walls splitting the cavity along X into equal bays.',
  },
  corners: {
    type: 'select', default: 'round',
    options: [
      { value: 'round', label: 'Rounded' },
      { value: 'chamfer', label: 'Chamfered' },
      { value: 'square', label: 'Square' },
    ],
    label: 'Corner style',
  },
  feet: {
    type: 'boolean', default: false,
    label: 'Recessed base',
    help: 'Inset the bottom edge so the tray sits on a small lip (stackable look).',
  },
});

// --- Derived dimensions -----------------------------------------------------
// The cavity must leave a wall on each side and a floor underneath. Clamp the
// inner size to a sane minimum so extreme slider combos (thick wall + narrow
// box) still produce a real, manifold cavity instead of an empty/degenerate one.
const MIN_INNER = 1.0; // never let an inner dimension collapse below this
const innerW = Math.max(MIN_INNER, p.width - 2 * p.wall);
const innerD = Math.max(MIN_INNER, p.depth - 2 * p.wall);
const innerH = Math.max(MIN_INNER, p.height - p.floor); // open top: no ceiling
const cavityRadius = Math.max(0, p.radius - p.wall);

// A rounded rectangle as a CrossSection, centered on the origin. The join style
// is chosen by the `corners` select: Round -> arcs, Miter (no shrink/expand) ->
// crisp square, and a Round shrink/expand at a small radius reads as a chamfer.
//
// IMPORTANT: a round/chamfer corner is built by an inward `offset(-r)` then an
// outward `offset(+r)`. If `r` reaches half the SHORTER side the inward pass
// erases the whole polygon (verified: offset(-w/2,'Round') -> area 0), leaving
// an empty solid. The Customizer lets `radius` run to 40 while `width` can be as
// low as 20, so we cap the *effective* radius just under half the shorter side.
function plate(w, d, r, style) {
  const base = CrossSection.square([w, d], true);
  const rEff = Math.min(r, Math.min(w, d) / 2 - 0.01);
  if (style === 'square' || rEff <= 0) return base;
  if (style === 'chamfer') {
    // Offset out then back with MITERED joins clipped short = a flat 45° cut.
    return base.offset(rEff, 'Miter', 1).offset(-rEff, 'Miter', 1);
  }
  // Rounded: shrink with round joins then grow back — corners become true arcs
  // of radius `rEff` while the bounding box is preserved.
  return base.offset(-rEff, 'Round').offset(rEff, 'Round');
}

// --- Outer shell ------------------------------------------------------------
const outer = Manifold.extrude(plate(p.width, p.depth, p.radius, p.corners), p.height);

// --- Cavity -----------------------------------------------------------------
// Raised by the floor thickness; tall enough to reach (and break through) the
// top so the tray is open. Extend it a hair above the rim so the top face is a
// clean single loop rather than a coincident-face boolean seam.
const cavity = Manifold.extrude(
  plate(innerW, innerD, cavityRadius, p.corners),
  innerH + 1,
).translate(0, 0, p.floor);

let tray = outer.subtract(cavity);

// --- Internal dividers ------------------------------------------------------
// Evenly spaced cross walls (constant `wall` thickness) spanning the cavity in
// Y, splitting the X span into `dividers + 1` equal bays. Each wall overlaps the
// floor and side walls so the union is a single solid.
if (p.dividers > 0) {
  const n = p.dividers;
  const bay = (innerW - n * p.wall) / (n + 1); // width of each open bay
  if (bay >= 0.5) {
    const wallH = innerH; // rise from the floor up to the rim
    const divider = Manifold.cube([p.wall, innerD + 1, wallH], true)
      .translate(0, 0, p.floor + wallH / 2);
    const walls = [];
    for (let i = 0; i < n; i++) {
      // Left edge of cavity is at -innerW/2. Step across one bay + one wall.
      const x = -innerW / 2 + bay + p.wall / 2 + i * (bay + p.wall);
      walls.push(divider.translate(x, 0, 0));
    }
    tray = tray.add(Manifold.union(walls));
  }
}

// --- Optional recessed base -------------------------------------------------
// Carve a shallow rebate into the underside so a stack of trays nests. Kept
// smaller than the floor so it never punches through into the cavity.
if (p.feet) {
  const inset = Math.min(p.wall, 1.5);
  const recessDepth = Math.min(p.floor * 0.5, 1.5);
  if (inset > 0.2 && recessDepth > 0.2) {
    const rebate = Manifold.extrude(
      plate(p.width - 2 * inset, p.depth - 2 * inset, Math.max(0, p.radius - inset), p.corners),
      recessDepth + 1,
    ).translate(0, 0, -1); // start below z=0, cut up into the floor
    tray = tray.subtract(rebate);
  }
}

return tray;
